create or replace function public.can_view_sensitive_detail(p_project_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  -- Truthful launch-safe enforcement: only detail visibility can read sensitive detail rows.
  -- Summary/redacted views are deferred to dedicated read models/RPCs.
  select public.effective_finance_visibility(p_project_id) = 'detail';
$$;

create or replace function public.actor_finance_visibility_delegate_cap(p_project_id uuid, p_actor uuid)
returns integer
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_role text;
  v_fin text;
begin
  v_role := public.project_role_for_profile(p_project_id, p_actor);
  if v_role is null then
    return -1;
  end if;

  if v_role = 'owner' then
    return public.finance_visibility_rank('detail');
  end if;

  select pm.finance_visibility
  into v_fin
  from public.project_members pm
  where pm.project_id = p_project_id
    and pm.profile_id = p_actor;

  if v_role = 'co_owner' and v_fin = 'none' then
    return public.finance_visibility_rank('summary');
  end if;

  return coalesce(public.finance_visibility_rank(v_fin), -1);
end;
$$;

