create or replace function public.effective_finance_visibility(p_project_id uuid)
returns text
language plpgsql
stable
security definer
set search_path = public
as $$
declare
  v_uid uuid := auth.uid();
  v_fin text;
  v_role text;
begin
  if v_uid is null then
    return null;
  end if;

  v_role := public.project_role_for_profile(p_project_id, v_uid);
  if v_role is null then
    return null;
  end if;

  if v_role = 'owner' then
    return 'detail';
  end if;

  select pm.finance_visibility
  into v_fin
  from public.project_members pm
  where pm.project_id = p_project_id
    and pm.profile_id = v_uid;

  if v_role = 'co_owner' and (v_fin = 'none' or v_fin is null) then
    return 'summary';
  end if;

  return coalesce(v_fin, 'none');
end;
$$;

