create or replace function public.can_access_storage_object(p_storage_object_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select
    exists (
      select 1
      from public.document_versions dv
      join public.documents d
        on d.id = dv.document_id
      where dv.storage_object_id = p_storage_object_id
        and dv.is_current = true
        and public.can_access_project(d.project_id)
        and (
          d.visibility_class = 'shared_project'
          or public.can_view_internal_documents(d.project_id)
        )
    )
  or exists (
      select 1
      from public.project_media pm
      where pm.storage_object_id = p_storage_object_id
        and public.can_access_project(pm.project_id)
        and (
          pm.visibility_class = 'shared_project'
          or public.can_view_internal_documents(pm.project_id)
        )
    );
$$;

